const fileName = "20260409-Chargerent-1.1.1.0-OU-FOTA.pac";
const publicBaseUrl = "http://34.56.244.66:1880";
const fileUrl = publicBaseUrl + "/firmware/" + fileName;
const fileSize = Buffer.isBuffer(msg.payload) ? msg.payload.length : Number(msg.payload?.length || 0);

if (!fileSize) {
    msg.statusCode = 500;
    msg.headers = { "Content-Type": "application/json; charset=utf-8" };
    msg.payload = {
        code: 500,
        type: 0,
        data: "",
        msg: "Firmware file is missing or empty",
        time: Date.now()
    };
    return msg;
}

msg.statusCode = 200;
msg.headers = {
    "Content-Type": "application/json; charset=utf-8",
    "Cache-Control": "no-store"
};
msg.payload = {
    code: 200,
    type: 0,
    data: `${fileName},${fileSize},${fileUrl}`,
    msg: "ok",
    time: Date.now()
};

node.warn(`Raw VM firmware metadata ${msg.req?.path || msg.req?.url || ""}: ${msg.payload.data}`);
return msg;
